sql:
SELECT indicator_id, AVG(score) as Average_Score
FROM country_indicators
GROUP BY indicator_id;

SELECT COUNT(*) 
FROM country_indicators 
WHERE score > 2;

SELECT DISTINCT country_name
FROM countries
WHERE gdp > 100000;

SELECT indicator_id, score, confidence_interval, year_id
FROM country_indicators
WHERE confidence_interval > (SELECT AVG(confidence_interval) FROM country_indicators);

SELECT country_name, capital
FROM countries
WHERE country_id > 50;

SELECT country_name, population, gdp, capital
FROM countries
WHERE gdp > (SELECT AVG(gdp) FROM countries);

